problems.explanation:
The leap-year rule is: a year divisible by $4$ is a leap year, except years divisible by $100$ are not leap years unless they are also divisible by $400$.

    bool isLeap(int y) {
        return (y % 4 == 0) && (y % 100 != 0 || y % 400 == 0);
    }

    int daysInMonth(int y, int m) {
        static const int days[] = {31,28,31,30,31,30,31,31,30,31,30,31};
        if (m == 2 && isLeap(y)) return 29;
        return days[m - 1];
    }

    void addDays(int& y, int& m, int& d, int n) {
        while (n > 0) {
            int left = daysInMonth(y, m) - d;
            if (n <= left) {
                d += n;
                return;
            }
            n -= left + 1;
            d = 1;
            if (++m == 13) {
                m = 1;
                ++y;
            }
        }
    }

This version is faster than adding one day at a time when $n$ is large, because it jumps month by month.

