problems.answer:
Use Newton's method:

    double mySqrt(double x, double tol = 1e-12) {
        if (x < 0.0) throw std::domain_error("negative input");
        if (x == 0.0) return 0.0;
        double g = x >= 1.0 ? x : 1.0;
        while (std::abs(g * g - x) > tol * std::max(1.0, x)) {
            g = 0.5 * (g + x / g);
        }
        return g;
    }

